#include<bits/stdc++.h>
using namespace std;
long long b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long sum,max1;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].lson=a[x].rson=0;
            a[x].sum=a[x].max1=b[l];
            return x;
        }
        long long mid=((l+r)>>1);
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r)
    {
        if(a[x].r<l||a[x].l>r)
        {
            return;
        }
        if(a[x].max1<=1)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].sum=a[x].max1=(long long)(floor(sqrt(a[x].sum)));
            return;
        }
        update(a[x].lson,l,r);
        update(a[x].rson,l,r);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].r<l||a[x].l>r)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r);
    }
}t;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    int m;
    scanf("%d",&m);
    while(m--)
    {
        int k,l,r;
        scanf("%d%d%d",&k,&l,&r);
        if(l>r)
        {
            swap(l,r);
        }
        if(k==0)
        {
            t.update(1,l,r);
        }
        else
        {
            printf("%lld\n",t.getsum(1,l,r));
        }
    }
    return 0;
}
